  "evidence": "[2026-07-16 12:50:59 TP1] Failed to deserialize from CUDA IPC handle (HIP error: invalid device pointer) at reconstruct_on_target_device in cuda_ipc_transport_utils.py:488 when trying to open a stale IPC handle whose backing device buffer was recycled"
}

